mapper.select:
/* dr 감축량 조회 */ select dr_rst_idx, site_id, start_timestamp, start_date, end_timestamp, end_date, cbl_amt, act_amt, (cbl_amt-goal_power) as cbl_power, /* 계약용량 = 기준부하 - 목표전력 */ contract_power, goal_power, reward_amt, reg_date, mod_date , (cbl_amt-act_amt) as reduce_amt, (cbl_amt-act_amt)/(cbl_amt-goal_power) as fulfill_per /* 이행률 */ from tb_dr_result where site_id = #{siteId }
and start_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
order by start_timestamp

/* 기준부하 조회 */ select cbl_idx, site_id, start_timestamp, start_date, end_timestamp, end_date, cbl, cml, reg_date, mod_date from tb_cbl where site_id = #{siteId }
and start_date = str_to_date(#{cblStartFrom },'%Y%m%d%H%i%s')
order by start_timestamp
